						}
					},
					legend: {
						bottom: '5%',
						right: 'center',
						// icon: 'rect',//ељҐзКґ  з±їеЮЛеМЕжЛђ circleпЉМrect,lineпЉМroundRectпЉМtriangleпЉМdiamondпЉМpinпЉМarrowпЉМnone
						itemWidth: 8, // иЃЊзљЃеЃљеЇ¶
						itemHeight: 8, // иЃЊзљЃйЂШеЇ¶
						// itemGap: 40, // иЃЊзљЃдЄ§дЄ™legendдєЛйЧізЪДйЧіиЈЭ
						// data:this.legendData,
						data: [{
								name: 'иЙѓе•љ', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								// textStyle: {
								// 	color: '#2DC3FB' // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								// }
							},
							{
								name: 'ж≠£еЄЄ', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								// textStyle: {
								// 	color: '#FDD43C' // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								// }
							},
							{
								name: 'еЕ≥ж≥®', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								// textStyle: {
								// 	color: '#FDD43C' // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								// }
							},
							{
								name: 'йЂШй£ОйЩ©', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								// textStyle: {
								// 	color: '#FDD43C' // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								// }
							}
						]

					},
					xAxis: {
						type: 'category',
						data: this.xAxisData,
						// data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
					},
					yAxis: {
						type: 'value'
					},
					radius: '90%',
					series: this.series,
					// series: [

					// 	{
					// 		name: 'иЙѓе•љ',
					// 		data: [140, 230, 274, 218, 135, 157, 240],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'ж≠£еЄЄ',
					// 		data: [130, 230, 234, 228, 135, 147, 260],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'еЕ≥ж≥®',
